@startuml
' UML Diagram: Prototype Pattern in Iluwar

package "com" {
  package "prototype" {
    class ElfBeast {
      + ElfBeast()
      + clone() : Beast
      + toString() : String
    }

    class OrcBeast {
      + OrcBeast()
      + clone() : Beast
      + toString() : String
    }

    class ElfWarlord {
      + ElfWarlord()
      + clone() : Warlord
      + toString() : String
    }

    class OrcWarlord {
      + OrcWarlord()
      + clone() : Warlord
      + toString() : String
    }

    class ElfMage {
      + ElfMage()
      + clone() : Mage
      + toString() : String
    }

    class OrcMage {
      + OrcMage()
      + clone() : Mage
      + toString() : String
    }

    class Beast {
      + Beast()
      + clone() : Beast
    }

    class Warlord {
      + Warlord()
      + clone() : Warlord
    }

    class Mage {
      + Mage()
      + clone() : Mage
    }

    class Prototype {
      + Prototype()
      + clone() : Object
    }

    class HeroFactoryImpl {
      - beast : Beast
      - mage : Mage
      - warlord : Warlord
      + HeroFactoryImpl(mage : Mage, warlord : Warlord, beast : Beast)
      + createBeast() : Beast
      + createMage() : Mage
      + createWarlord() : Warlord
    }

    interface HeroFactory {
      + createBeast() : Beast
      + createMage() : Mage
      + createWarlord() : Warlord
    }

    class App {
      + App()
      + main(args : String[])
    }
  }
}

' Relationships

ElfBeast ..|> Beast
OrcBeast ..|> Beast
ElfWarlord ..|> Warlord
OrcWarlord ..|> Warlord
ElfMage ..|> Mage
OrcMage ..|> Mage

Beast ..|> Prototype
Warlord ..|> Prototype
Mage ..|> Prototype

HeroFactoryImpl --|> HeroFactory

HeroFactoryImpl --> Beast : -beast
HeroFactoryImpl --> Warlord : -warlord
HeroFactoryImpl --> Mage : -mage

App --> HeroFactoryImpl

@enduml
